effect.shader:
const vec3 luminanceWeighting = vec3(0.2126, 0.7152, 0.0722);

void main() {
    vec4 blur = texture2DCv(hblur.texture, acScreenNorm.st);
    vec4 base = texture2DCv(inputImg.texture, acScreenNorm.st);
    float blurY = dot(blur.rgb, luminanceWeighting);
    float baseY = dot(base.rgb, luminanceWeighting);
    vec4 adjColor = base * (1.+amount) - (blur*amount);
    float t = step(threshold,abs(blurY-baseY)*4.);
    t = smoothstep(threshold*0.75, (threshold+1.01)/2., abs(blurY-baseY)*4.);
    gl_FragColor = showMask ? vec4(t,0.,0.,1.)*base.a : mix(base,adjColor,t);
}
